     1	/**
     2	 * View-tabs persistence — spec §11.3 follow-up (T-06).
     3	 *
     4	 * Serializes the open `TabsState` to `localStorage` so reloads keep
     5	 * the user's open views. The hydration step drops tabs whose
     6	 * `targetId` no longer resolves to an element in the store (the
     7	 * underlying view was deleted between sessions).
     8	 */
     9	
    10	import type { TabsState, ViewTab } from './tabsModel';
    11	
    12	const STORAGE_KEY = 'bim-ai:tabs-v1';
    13	
    14	/** Stable serialization shape — `tabs` array + `activeId`. Versioned so
    15	 * a future schema bump can be detected and discarded. */
    16	interface PersistedTabsV1 {
    17	  v: 1;
    18	  tabs: ViewTab[];
    19	  activeId: string | null;
    20	}
    21	
    22	export function persistTabs(state: TabsState): void {
    23	  if (typeof localStorage === 'undefined') return;
    24	  const payload: PersistedTabsV1 = { v: 1, tabs: state.tabs, activeId: state.activeId };
    25	  try {
    26	    localStorage.setItem(STORAGE_KEY, JSON.stringify(payload));
    27	  } catch {
    28	    /* storage may be disabled (quota / private mode) — silent */
    29	  }
    30	}
    31	
    32	export function readPersistedTabs(): TabsState | null {
    33	  if (typeof localStorage === 'undefined') return null;
    34	  try {
    35	    const raw = localStorage.getItem(STORAGE_KEY);
    36	    if (!raw) return null;
    37	    const parsed = JSON.parse(raw) as Partial<PersistedTabsV1> | null;
    38	    if (!parsed || parsed.v !== 1 || !Array.isArray(parsed.tabs)) return null;
    39	    return {
    40	      tabs: parsed.tabs.filter((t): t is ViewTab => isViewTab(t)),
    41	      activeId: typeof parsed.activeId === 'string' ? parsed.activeId : null,
    42	    };
    43	  } catch {
    44	    return null;
    45	  }
    46	}
    47	
    48	/** Drop tabs whose `targetId` no longer resolves to an element. Used
    49	 * after the seed bootstrap completes — orphaned tabs (e.g. a sheet
    50	 * deleted while the user was offline) get pruned silently. */
    51	export function pruneTabsAgainstElements(
    52	  state: TabsState,
    53	  elementsById: Record<string, unknown>,
    54	): TabsState {
    55	  const survivors = state.tabs.filter(
    56	    (t) => !t.targetId || Object.prototype.hasOwnProperty.call(elementsById, t.targetId),
    57	  );
    58	  if (survivors.length === state.tabs.length) return state;
    59	  const activeStillThere = survivors.some((t) => t.id === state.activeId);
    60	  return {
    61	    tabs: survivors,
    62	    activeId: activeStillThere ? state.activeId : (survivors[0]?.id ?? null),
    63	  };
    64	}
    65	
    66	export function clearPersistedTabs(): void {
    67	  if (typeof localStorage === 'undefined') return;
    68	  try {
    69	    localStorage.removeItem(STORAGE_KEY);
    70	  } catch {
    71	    /* ignore */
    72	  }
    73	}
    74	
    75	function isViewTab(t: unknown): boolean {
    76	  if (!t || typeof t !== 'object') return false;
    77	  const r = t as Record<string, unknown>;
    78	  return typeof r.id === 'string' && typeof r.kind === 'string' && typeof r.label === 'string';
    79	}

