    const restored = readPersistedTabs();
    expect(restored).toEqual({
      tabs: [{ id: 'sheet:a1', kind: 'sheet', targetId: 'a1', label: 'Sheet · A1' }],
      activeId: 'sheet:a1',
    });
  });

